     7→async function request<T>(path: string, options?: RequestInit): Promise<T> {
     8→  const res = await fetch(`${API_URL}${path}`, {
     9→    headers: { "Content-Type": "application/json" },
    10→    ...options,
    11→  });
    12→  if (!res.ok) {
    13→    const body = await res.json().catch(() => ({}));
