}

function StatCard({ label, value }: { label: string; value: string | number }) {
  return (
    <div className="bg-white rounded-xl border border-zinc-200 p-4 text-center">
      <p className="text-2xl font-bold">{value}</p>
      <p className="text-xs text-zinc-500 mt-1">{label}</p>
    </div>
  );
}

const STT_MODELS = [
  { value: "nova-2", label: "Nova 2 (default)" },
  { value: "nova-2-general", label: "Nova 2 General" },
  { value: "nova-2-phonecall", label: "Nova 2 Phone Call" },
  { value: "nova-2-meeting", label: "Nova 2 Meeting" },
];

function STTSettings({
  config,
  onChange,
}: {
  config: STTConfig;
  onChange: (config: STTConfig) => void;
}) {
  const [localUtterance, setLocalUtterance] = useState(config.utterance_end_ms);
  const [localEndpointing, setLocalEndpointing] = useState(config.endpointing);
  const [saving, setSaving] = useState(false);

  const save = useCallback(
    async (patch: Partial<STTConfig>) => {
      setSaving(true);
      try {
        const updated = await updateSTTConfig(patch);
        onChange(updated);
      } catch (err) {
        console.error("[Admin] STT config update failed:", err);
      } finally {
        setSaving(false);
      }
    },
    [onChange],
  );

  return (
    <section className="bg-white rounded-xl border border-zinc-200 p-6 mb-6">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-lg font-semibold">STT Settings</h2>
        {saving && <span className="text-xs text-zinc-400">Saving...</span>}
      </div>

      <div className="space-y-5">
        {/* Utterance End */}
        <div>
          <label className="block text-sm font-medium text-zinc-700 mb-1">
            Utterance End: {localUtterance}ms
          </label>
          <input
            type="range"
            min={500}
            max={3000}
            step={100}
            value={localUtterance}
            onChange={(e) => setLocalUtterance(Number(e.target.value))}
            onMouseUp={() => save({ utterance_end_ms: localUtterance })}
            onTouchEnd={() => save({ utterance_end_ms: localUtterance })}
            className="w-full accent-blue-500"
          />
          <div className="flex justify-between text-xs text-zinc-400 mt-1">
            <span>500ms (fast)</span>
            <span>3000ms (slow)</span>
          </div>
        </div>

        {/* Endpointing (Sensitivity) */}
        <div>
          <label className="block text-sm font-medium text-zinc-700 mb-1">
            Sensitivity (Endpointing): {localEndpointing}ms
          </label>
          <input
            type="range"
            min={10}
            max={500}
            step={10}
            value={localEndpointing}
            onChange={(e) => setLocalEndpointing(Number(e.target.value))}
            onMouseUp={() => save({ endpointing: localEndpointing })}
            onTouchEnd={() => save({ endpointing: localEndpointing })}
            className="w-full accent-blue-500"
          />
          <div className="flex justify-between text-xs text-zinc-400 mt-1">
            <span>10ms (fast/sensitive)</span>
            <span>500ms (slow/patient)</span>
          </div>
        </div>

        {/* Model */}
        <div>
          <label className="block text-sm font-medium text-zinc-700 mb-1">
            Model
          </label>
          <select
            value={config.model}
            onChange={(e) => save({ model: e.target.value })}
            className="w-full border border-zinc-200 rounded-lg px-3 py-2 text-sm bg-white"
          >
            {STT_MODELS.map((m) => (
              <option key={m.value} value={m.value}>
                {m.label}
              </option>
            ))}
          </select>
        </div>

        {/* Smart Format */}
        <div className="flex items-center justify-between">
          <div>
            <p className="text-sm font-medium text-zinc-700">Smart Format</p>
            <p className="text-xs text-zinc-400">
              Auto-punctuation, numerals, formatting
            </p>
          </div>
          <button
            onClick={() => save({ smart_format: !config.smart_format })}
            className={`relative w-11 h-6 rounded-full transition-colors ${
              config.smart_format ? "bg-blue-500" : "bg-zinc-300"
            }`}
          >
            <span
              className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform ${
                config.smart_format ? "translate-x-5" : "translate-x-0"
              }`}
            />
          </button>
        </div>
      </div>
    </section>
  );
}

function formatElapsed(startedAt: string, completedAt: string | null): string {
  const start = new Date(startedAt).getTime();
  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
  const seconds = Math.round((end - start) / 1000);
  if (seconds < 60) return `${seconds}s`;
  return `${Math.floor(seconds / 60)}m ${seconds % 60}s`;
}

const STATUS_STYLES: Record<string, string> = {
  running: "bg-blue-100 text-blue-700",
  completed: "bg-green-100 text-green-700",
  failed: "bg-red-100 text-red-700",
};

function ScrapeJobsSection({ jobs }: { jobs: ScrapeJob[] }) {
  const visible = jobs.slice(0, 10);

  return (
    <section className="bg-white rounded-xl border border-zinc-200 p-6 mb-6">
      <h2 className="text-lg font-semibold mb-4">Scrape Jobs</h2>
      {visible.length === 0 ? (
        <p className="text-zinc-400">No scrape jobs recorded</p>
      ) : (
        <div className="divide-y divide-zinc-100">
          {visible.map((job) => (
            <div key={job.user_id + job.started_at} className="py-3 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <span
                  className={`text-xs font-medium px-2 py-0.5 rounded-full ${STATUS_STYLES[job.status] || "bg-zinc-100 text-zinc-600"}`}
                >
                  {job.status}
                </span>
                <div>
                  <p className="font-medium text-sm">{job.user_name}</p>
                  <p className="text-xs text-zinc-500">
                    {job.phase} &middot; {job.purchases_found} purchases &middot; {formatElapsed(job.started_at, job.completed_at)}
                  </p>
                </div>
              </div>
              {job.error && (
                <p className="text-xs text-red-500 max-w-xs truncate" title={job.error}>
                  {job.error}
                </p>
              )}
            </div>
          ))}
        </div>
      )}
    </section>
  );
}

