   199→        <input
   200→          value={name}
   201→          onChange={(e) => setName(e.target.value)}
   202→          placeholder="Enter your name"
   203→          className="w-full px-4 py-3 border border-zinc-200 rounded-xl text-base focus:outline-none focus:ring-2 focus:ring-zinc-900"
   204→        />
