     5→
     6→declare global {
     7→  interface Window {
     8→    google?: {
     9→      accounts: {
    10→        oauth2: {
    11→          initCodeClient: (config: {
    12→            client_id: string;
    13→            scope: string;
    14→            ux_mode: string;
    15→            callback: (response: { code: string }) => void;
    16→          }) => { requestCode: () => void };
