     3→import { useEffect, useState, useRef } from "react";
     4→import { getQueueStatus, joinQueue, leaveQueue, QueueInfo } from "@/lib/api";
     5→
     6→interface QueueStatusProps {
     7→  userId: string;
     8→  onBecameActive?: () => void;
     9→  onLeave?: () => void;
    10→}
    11→
    12→export default function QueueStatus({ userId, onBecameActive, onLeave }: QueueStatusProps) {
    13→  const [queue, setQueue] = useState<QueueInfo | null>(null);
    14→  const [error, setError] = useState("");
    15→  const [leaving, setLeaving] = useState(false);
    16→  const firedRef = useRef(false);
    17→
    18→  useEffect(() => {
    19→    let cancelled = false;
    20→    let timer: ReturnType<typeof setInterval>;
    21→
    22→    async function init() {
    23→      try {
    24→        const info = await joinQueue(userId);
    25→        if (!cancelled) setQueue(info);
    26→      } catch (err) {
    27→        if (!cancelled) setError(err instanceof Error ? err.message : "Failed to join queue");
    28→      }
    29→    }
    30→
    31→    init();
    32→
    33→    // Poll every 5 seconds
    34→    timer = setInterval(async () => {
    35→      try {
    36→        const info = await getQueueStatus(userId);
    37→        if (!cancelled) setQueue(info);
    38→      } catch {
    39→        // Ignore polling errors
    40→      }
    41→    }, 5000);
    42→
    43→    return () => {
    44→      cancelled = true;
    45→      clearInterval(timer);
    46→    };
    47→  }, [userId]);
    48→
    49→  // Fire onBecameActive exactly once
    50→  useEffect(() => {
    51→    if (queue?.status === "active" && !firedRef.current && onBecameActive) {
    52→      firedRef.current = true;
    53→      onBecameActive();
    54→    }
    55→  }, [queue?.status, onBecameActive]);
    56→
    57→  async function handleLeave() {
    58→    setLeaving(true);
    59→    try {
    60→      await leaveQueue(userId);
    61→      onLeave?.();
    62→    } catch {
    63→      setLeaving(false);
    64→      setError("Failed to leave queue. Please try again.");
    65→    }
    66→  }
    67→
    68→  if (error) {
    69→    return (
    70→      <div className="text-center text-red-500">
    71→        <p>{error}</p>
    72→      </div>
    73→    );
    74→  }
    75→
    76→  if (!queue) {
    77→    return (
    78→      <div className="text-center text-zinc-500">
    79→        <p>Joining the queue...</p>
    80→      </div>
    81→    );
    82→  }
    83→
    84→  if (queue.status === "active") {
    85→    return (
    86→      <div className="flex flex-col items-center gap-4">
    87→        <div className="w-20 h-20 rounded-full bg-green-500 flex items-center justify-center text-white text-4xl">
    88→          ✓
    89→        </div>
    90→        <h2 className="text-2xl font-bold">It&apos;s your turn!</h2>
    91→        <p className="text-zinc-500">Head to the mirror to begin your session.</p>
    92→        <button
    93→          onClick={handleLeave}
    94→          disabled={leaving}
    95→          className="mt-4 text-sm text-zinc-400 hover:text-zinc-600 transition-colors disabled:opacity-50"
    96→        >
    97→          {leaving ? "Leaving..." : "Leave Queue"}
    98→        </button>
    99→      </div>
   100→    );
   101→  }
   102→
   103→  return (
   104→    <div className="flex flex-col items-center gap-5">
   105→      <h2 className="text-xl font-bold">You&apos;re in the queue</h2>
   106→      <div className="w-24 h-24 rounded-full bg-zinc-100 flex items-center justify-center text-4xl font-bold">
   107→        {queue.position}
   108→      </div>
   109→      <p className="text-zinc-500 text-center">
   110→        {queue.total_ahead === 0
   111→          ? "You're next! Hang tight."
   112→          : `${queue.total_ahead} ${queue.total_ahead === 1 ? "person" : "people"} ahead of you`}
   113→      </p>
   114→      <p className="text-zinc-400 text-sm">
   115→        This page updates automatically.
   116→      </p>
   117→      <button
   118→        onClick={handleLeave}
   119→        disabled={leaving}
   120→        className="mt-2 text-sm text-zinc-400 hover:text-zinc-600 transition-colors disabled:opacity-50"
   121→      >
   122→        {leaving ? "Leaving..." : "Leave Queue"}
   123→      </button>
   124→    </div>
   125→  );
   126→}
